    /// <summary>
    /// Represents data that has been sanitized/redacted for safe logging.
    /// </summary>
    public static class LogSanitizer
    {
        private static readonly HashSet<string> SensitiveHeaders = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "Authorization",
            "Cookie",
            "Set-Cookie",
            "X-Api-Key",
            "X-Auth-Token",
            "Proxy-Authorization",
            "X-Forwarded-For"
        };

        private static readonly HashSet<string> SensitiveBodyFields = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "password",
            "creditCardNumber",
            "credit_card",
            "cardNumber",
            "cvv",
            "ssn",
            "socialSecurityNumber",
            "secret",
            "token",
            "apiKey",
            "api_key",
            "accountNumber",
            "routingNumber",
            "dateOfBirth",
            "dob",
            "driverLicense"
        };

        public static string RedactValue(string value, int visibleChars = 4)
        {
            if (string.IsNullOrEmpty(value)) return "[empty]";
            if (value.Length <= visibleChars) return "***";
            return new string('*', value.Length - visibleChars) + value.Substring(value.Length - visibleChars);
        }

        public static Dictionary<string, string> SanitizeHeaders(IHeaderDictionary headers)
        {
            var sanitized = new Dictionary<string, string>();
            foreach (var header in headers)
            {
                if (SensitiveHeaders.Contains(header.Key))
                {
                    sanitized[header.Key] = "[REDACTED]";
                }
                else
                {
                    sanitized[header.Key] = header.Value.ToString();
                }
            }
            return sanitized;
        }

        public static string SanitizeBody(string rawBody)
        {
            if (string.IsNullOrWhiteSpace(rawBody)) return "[empty body]";

            try
            {
                var obj = JsonConvert.DeserializeObject<Dictionary<string, object>>(rawBody);
                if (obj == null) return "[null body]";

                var sanitized = new Dictionary<string, object>();
                foreach (var kvp in obj)
                {
                    if (SensitiveBodyFields.Contains(kvp.Key))
                    {
                        sanitized[kvp.Key] = "[REDACTED]";
                    }
                    else if (kvp.Key.Equals("email", StringComparison.OrdinalIgnoreCase) && kvp.Value != null)
                    {
                        // Partially redact email: show domain only
                        string email = kvp.Value.ToString();
                        int atIndex = email.IndexOf('@');
                        if (atIndex > 0)
                        {
                            sanitized[kvp.Key] = "***" + email.Substring(atIndex);
                        }
                        else
                        {
                            sanitized[kvp.Key] = "[REDACTED]";
                        }
                    }
                    else
                    {
                        sanitized[kvp.Key] = kvp.Value;
                    }
                }

                return JsonConvert.SerializeObject(sanitized);
            }
            catch
            {
                // If not JSON, log content type indicator only
                return $"[Non-JSON body, length={rawBody.Length}]";
            }
        }

        public static string SanitizeConnectionString(string connectionString)
        {
            if (string.IsNullOrEmpty(connectionString)) return "[not configured]";

            try
            {
                var builder = new SqlConnectionStringBuilder(connectionString);
                if (!string.IsNullOrEmpty(builder.Password))
                {
                    builder.Password = "[REDACTED]";
                }
                if (!string.IsNullOrEmpty(builder.UserID))
                {
                    builder.UserID = "[REDACTED]";
                }
                return builder.ToString();
            }
            catch
            {
                return "[connection string present but not displayed]";
            }
        }

        public static string SanitizeException(Exception ex)
        {
            // Log exception type, message, and stack trace but scrub known sensitive patterns
            if (ex == null) return "[no exception]";

            string message = ex.Message;
            // Remove potential connection strings from exception messages
            message = System.Text.RegularExpressions.Regex.Replace(
                message,
                @"(Password|Pwd)\s*=\s*[^;]+",
                "$1=[REDACTED]",
                System.Text.RegularExpressions.RegexOptions.IgnoreCase);

            return $"Type: {ex.GetType().FullName}, Message: {message}, StackTrace: {ex.StackTrace}";
        }
    }

